class Solution:
    def minFlipsMonoIncr(self, s):
        """
        :type s: str
        :rtype: int
        """
        ones = 0  # Count of 1s seen so far
        flips = 0  # Flips needed

        for char in s:
            if char == '1':
                ones += 1
            else:
                # Either flip this 0 to 1, or flip all previous 1s to 0
                flips = min(ones, flips + 1)

        return flips
